import { useState } from "react";
import { Plus, X } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "../components/ui/dialog";
import { Label } from "../components/ui/label";
import { Input } from "../components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "../components/ui/select";

const timeSlots = [
  "06:00 AM", "07:00 AM", "08:00 AM", "09:00 AM", "10:00 AM", "11:00 AM",
  "12:00 PM", "01:00 PM", "02:00 PM", "03:00 PM", "04:00 PM", "05:00 PM",
  "06:00 PM", "07:00 PM", "08:00 PM", "09:00 PM", "10:00 PM"
];

const weekDays = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
const fullWeekDays = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

const classTypes = [
  { name: "Yoga", color: "#8B5CF6" },
  { name: "HIIT", color: "#EF4444" },
  { name: "Spin", color: "#F59E0B" },
  { name: "CrossFit", color: "#10B981" },
  { name: "Boxing", color: "#EC4899" },
  { name: "Zumba", color: "#6366F1" },
  { name: "Pilates", color: "#14B8A6" },
];

const trainers = [
  "Sarah Johnson",
  "Mike Chen",
  "Emma Davis",
  "Alex Rodriguez",
  "James Wilson",
  "Tom Anderson",
  "Maria Garcia",
];

// Mock schedule data
const scheduleData: Record<number, Array<{ time: string; name: string; trainer: string; color: string; duration: number }>> = {
  0: [ // Monday
    { time: "06:00 AM", name: "Morning Yoga", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1 },
    { time: "07:00 AM", name: "HIIT Training", trainer: "Mike Chen", color: "#EF4444", duration: 1 },
    { time: "09:00 AM", name: "Spin Class", trainer: "Emma Davis", color: "#F59E0B", duration: 1 },
    { time: "06:00 PM", name: "CrossFit", trainer: "Alex Rodriguez", color: "#10B981", duration: 1.5 },
  ],
  1: [ // Tuesday
    { time: "06:00 AM", name: "Yoga", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1 },
    { time: "08:00 AM", name: "Boxing", trainer: "James Wilson", color: "#EC4899", duration: 1 },
    { time: "05:00 PM", name: "HIIT Training", trainer: "Mike Chen", color: "#EF4444", duration: 1 },
    { time: "07:00 PM", name: "Zumba", trainer: "Maria Garcia", color: "#6366F1", duration: 1 },
  ],
  2: [ // Wednesday
    { time: "07:00 AM", name: "Spin Class", trainer: "Emma Davis", color: "#F59E0B", duration: 1 },
    { time: "09:00 AM", name: "Pilates", trainer: "Sarah Johnson", color: "#14B8A6", duration: 1 },
    { time: "06:00 PM", name: "CrossFit", trainer: "Alex Rodriguez", color: "#10B981", duration: 1.5 },
  ],
  3: [ // Thursday
    { time: "06:00 AM", name: "Yoga", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1 },
    { time: "08:00 AM", name: "HIIT Training", trainer: "Mike Chen", color: "#EF4444", duration: 1 },
    { time: "06:00 PM", name: "Boxing", trainer: "James Wilson", color: "#EC4899", duration: 1 },
    { time: "08:00 PM", name: "Spin Class", trainer: "Emma Davis", color: "#F59E0B", duration: 1 },
  ],
  4: [ // Friday
    { time: "06:00 AM", name: "Morning Yoga", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1 },
    { time: "07:00 AM", name: "HIIT Training", trainer: "Mike Chen", color: "#EF4444", duration: 1 },
    { time: "05:00 PM", name: "Zumba", trainer: "Maria Garcia", color: "#6366F1", duration: 1 },
    { time: "07:00 PM", name: "CrossFit", trainer: "Alex Rodriguez", color: "#10B981", duration: 1.5 },
  ],
  5: [ // Saturday
    { time: "08:00 AM", name: "Yoga", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1.5 },
    { time: "10:00 AM", name: "Spin Class", trainer: "Emma Davis", color: "#F59E0B", duration: 1 },
    { time: "11:00 AM", name: "Boxing", trainer: "James Wilson", color: "#EC4899", duration: 1 },
  ],
  6: [ // Sunday
    { time: "09:00 AM", name: "Yoga & Meditation", trainer: "Sarah Johnson", color: "#8B5CF6", duration: 1.5 },
    { time: "11:00 AM", name: "Pilates", trainer: "Sarah Johnson", color: "#14B8A6", duration: 1 },
  ],
};

export function ScheduleManager() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    className: "",
    instructor: "",
    date: "",
    time: "",
    duration: "",
    capacity: "",
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log("Form submitted:", formData);
    setIsModalOpen(false);
    // Reset form
    setFormData({
      className: "",
      instructor: "",
      date: "",
      time: "",
      duration: "",
      capacity: "",
    });
  };

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Class Schedule Management</h1>
          <p className="text-gray-400 mt-1">View and manage weekly class schedule</p>
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="bg-[#39FF14] text-[#121212] px-6 py-3 rounded-lg font-bold hover:bg-[#2EE010] transition-colors flex items-center gap-2"
        >
          <Plus className="w-5 h-5" />
          Create New Class
        </button>
      </div>

      {/* Week Navigation */}
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-4 flex items-center justify-between">
        <button className="px-4 py-2 bg-[#121212] border border-[#2a2a2a] rounded-lg hover:border-[#39FF14]/30 transition-colors">
          ← Previous Week
        </button>
        <div className="text-white font-bold">March 24 - March 30, 2026</div>
        <button className="px-4 py-2 bg-[#121212] border border-[#2a2a2a] rounded-lg hover:border-[#39FF14]/30 transition-colors">
          Next Week →
        </button>
      </div>

      {/* Weekly Calendar Grid */}
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <div className="min-w-[1000px]">
            {/* Header Row */}
            <div className="grid grid-cols-8 border-b border-[#2a2a2a]">
              <div className="p-4 border-r border-[#2a2a2a]">
                <div className="text-sm text-gray-400">Time</div>
              </div>
              {weekDays.map((day, index) => (
                <div key={day} className="p-4 border-r border-[#2a2a2a] last:border-r-0">
                  <div className="text-center">
                    <div className="text-sm text-gray-400">{day}</div>
                    <div className="text-lg font-bold text-white mt-1">{24 + index}</div>
                  </div>
                </div>
              ))}
            </div>

            {/* Time Slots */}
            <div className="relative">
              {timeSlots.map((time) => (
                <div key={time} className="grid grid-cols-8 border-b border-[#2a2a2a] last:border-b-0 min-h-[80px]">
                  <div className="p-3 border-r border-[#2a2a2a] flex items-start">
                    <span className="text-sm text-gray-400">{time}</span>
                  </div>

                  {weekDays.map((_, dayIndex) => {
                    const classesForDay = scheduleData[dayIndex] || [];
                    const classAtTime = classesForDay.find(c => c.time === time);

                    return (
                      <div
                        key={dayIndex}
                        className="border-r border-[#2a2a2a] last:border-r-0 p-2 hover:bg-[#121212] transition-colors cursor-pointer"
                      >
                        {classAtTime && (
                          <div
                            className="rounded-lg p-3 h-full border-l-4 shadow-lg"
                            style={{
                              backgroundColor: `${classAtTime.color}15`,
                              borderLeftColor: classAtTime.color,
                            }}
                          >
                            <div className="font-bold text-sm text-white mb-1">{classAtTime.name}</div>
                            <div className="text-xs text-gray-400">{classAtTime.trainer}</div>
                            <div className="text-xs text-gray-500 mt-1">{classAtTime.duration}h</div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Create Class Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="bg-[#1a1a1a] border border-[#2a2a2a] text-white max-w-lg">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold">Create New Class</DialogTitle>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="space-y-4 mt-4">
            <div className="space-y-2">
              <Label htmlFor="className">Class Name</Label>
              <Select
                value={formData.className}
                onValueChange={(value) => setFormData({ ...formData, className: value })}
              >
                <SelectTrigger className="bg-[#121212] border-[#2a2a2a]">
                  <SelectValue placeholder="Select class type" />
                </SelectTrigger>
                <SelectContent className="bg-[#1a1a1a] border-[#2a2a2a]">
                  {classTypes.map((classType) => (
                    <SelectItem key={classType.name} value={classType.name}>
                      <div className="flex items-center gap-2">
                        <div
                          className="w-3 h-3 rounded-full"
                          style={{ backgroundColor: classType.color }}
                        />
                        {classType.name}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="instructor">Instructor</Label>
              <Select
                value={formData.instructor}
                onValueChange={(value) => setFormData({ ...formData, instructor: value })}
              >
                <SelectTrigger className="bg-[#121212] border-[#2a2a2a]">
                  <SelectValue placeholder="Select instructor" />
                </SelectTrigger>
                <SelectContent className="bg-[#1a1a1a] border-[#2a2a2a]">
                  {trainers.map((trainer) => (
                    <SelectItem key={trainer} value={trainer}>
                      {trainer}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="date">Date</Label>
                <Input
                  id="date"
                  type="date"
                  value={formData.date}
                  onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                  className="bg-[#121212] border-[#2a2a2a]"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="time">Time</Label>
                <Input
                  id="time"
                  type="time"
                  value={formData.time}
                  onChange={(e) => setFormData({ ...formData, time: e.target.value })}
                  className="bg-[#121212] border-[#2a2a2a]"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="duration">Duration (minutes)</Label>
                <Input
                  id="duration"
                  type="number"
                  placeholder="60"
                  value={formData.duration}
                  onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
                  className="bg-[#121212] border-[#2a2a2a]"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="capacity">Max Capacity</Label>
                <Input
                  id="capacity"
                  type="number"
                  placeholder="20"
                  value={formData.capacity}
                  onChange={(e) => setFormData({ ...formData, capacity: e.target.value })}
                  className="bg-[#121212] border-[#2a2a2a]"
                />
              </div>
            </div>

            <div className="flex gap-3 pt-4">
              <button
                type="button"
                onClick={() => setIsModalOpen(false)}
                className="flex-1 px-4 py-3 bg-[#121212] border border-[#2a2a2a] rounded-lg hover:border-[#39FF14]/30 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="flex-1 px-4 py-3 bg-[#39FF14] text-[#121212] rounded-lg font-bold hover:bg-[#2EE010] transition-colors"
              >
                Create Class
              </button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}
